import sys

def int_to_roman(num):
    val = [
        1000, 900, 500, 400,
        100, 90, 50, 40,
        10, 9, 5, 4,
        1
    ]
    syms = [
        "M", "CM", "D", "CD",
        "C", "XC", "L", "XL",
        "X", "IX", "V", "IV",
        "I"
    ]
    roman_num = ''
    i = 0
    while num > 0:
        for _ in range(num // val[i]):
            roman_num += syms[i]
            num -= val[i]
        i += 1
    return roman_num

def roman_to_int(s):
    rom_val = {'I': 1, 'V': 5, 'X': 10, 'L': 50, 'C': 100, 'D': 500, 'M': 1000}
    int_val = 0
    prev_val = 0
    for char in reversed(s):
        if rom_val[char] >= prev_val:
            int_val += rom_val[char]
        else:
            int_val -= rom_val[char]
        prev_val = rom_val[char]
    return int_val

if __name__ == '__main__':
    choice = input('Convert to Roman numerals (1) or to integer (2)? ')
    if choice == '1':
        number = int(input('Enter a number to convert to Roman numerals: '))
        print(int_to_roman(number))
    elif choice == '2':
        numeral = input('Enter Roman numerals to convert to integer: ').upper()
