class Stack:
    def __init__(self):
        self.items = []

    def push(self, item):
        self.items.append(item)
        print(f'Added {item} to the stack.')

    def pop(self):
        if not self.is_empty():
            item = self.items.pop()
            print(f'Removed {item} from the stack.')
            return item
        else:
            print('The stack is empty. Nothing to remove.')

    def is_empty(self):
        return len(self.items) == 0

    def peek(self):
        if not self.is_empty():
            return self.items[-1]
        else:
            print('The stack is empty. Nothing to peek.')

    def size(self):
        return len(self.items)

def main():
    stack = Stack()
    while True:
        print('\nStack Operations:\n1. Push item\n2. Pop item\n3. Peek item\n4. Check size\n5. Exit')
        choice = input('Enter your choice: ')

        if choice == '1':
            item = input('Enter item to push: ')
            stack.push(item)
        elif choice == '2':
            stack.pop()
        elif choice == '3':
            top_item = stack.peek()
            if top_item is not None:
                print(f'The top item is: {top_item}')
        elif choice == '4':
            print(f'Size of the stack: {stack.size()}')
        elif choice == '5':
            print('Exiting program.')
            break
        else:
            print('Invalid choice. Please try again.')

if __name__ == '__main__':
    main()
```

